import 'package:http/http.dart' as http;
import 'dart:convert';

class ApiService {
  final String baseUrl = "https://api.example.com"; // replace with your cloud API url
  final String iotDeviceUrl = "http://192.168.x.x"; // replace with your IoT device url
  http.Client client;

  ApiService() {
    client = http.Client();
  }

  Future<dynamic> getData(String endpoint) async {
    try {
      final response = await client.get('$baseUrl/$endpoint');
      
      if (response.statusCode == 200) {
        return jsonDecode(response.body);
      } else {
        throw Exception("Failed to load data");
      }
    } catch (e) {
      print(e); // error handling
      return null;
    }
  }

  Future<dynamic> postData(String endpoint, dynamic data) async {
    try {
      final response = await client.post('$baseUrl/$endpoint', body: jsonEncode(data));
      
      if (response.statusCode == 200 || response.statusCode == 201) {
        return jsonDecode(response.body);
      } else {
        throw Exception("Failed to post data");
      }
    } catch (e) {
      print(e); // error handling
      return null;
    }
  }
}